describe("JCS key ordering", () => {
  it("serialises keys in lexicographic order regardless of insertion order", () => {
    const entry = createEntry({ zebra: 1, apple: 2, mango: 3 });
    // createEntry should return the JCS-serialised string or an object
    // whose toString / JSON.stringify produces sorted keys
    const serialised =
      typeof entry === "string" ? entry : JSON.stringify(entry);
    const keys = [...serialised.matchAll(/"(\w+)":/g)].map((m) => m[1]);
    const dataKeys = keys.filter((k) =>
      ["zebra", "apple", "mango"].includes(k)
    );

    expect(dataKeys).toEqual([...dataKeys].sort());
  });

  it("produces identical bytes for the same payload with different key orders", () => {
    const a = createEntry({ b: 2, a: 1 });
    const b = createEntry({ a: 1, b: 2 });
    expect(a).toEqual(b);
  });

  it("handles nested objects with sorted keys at every level", () => {
    const entry = createEntry({ z: { y: 9, a: 1 }, a: { z: 9, a: 1 } });
    const serialised =
      typeof entry === "string" ? entry : JSON.stringify(entry);

    // Walk every object literal in the string and assert key order
    const objectPattern = /\{([^{}]+)\}/g;
    for (const [, body] of serialised.matchAll(objectPattern)) {
      const keys = [...body.matchAll(/"(\w+)":/g)].map((m) => m[1]);
      expect(keys).toEqual([...keys].sort());
    }
  });
});

